<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/auth.php';exigirRol(['usuario','admin','administracion_docente','administrador_docente']);$codigo=(string)($_GET['codigo']??'');$pdo=obtenerConexion();$sql="SELECT d.pedido_id FROM dte_documentos d JOIN pedidos p ON p.id=d.pedido_id WHERE d.codigo_generacion=:c AND p.payment_status='paid'";$a=['c'=>$codigo];if(!in_array(($_SESSION['usuario_rol']??''),['admin','administracion_docente','administrador_docente'],true)){$sql.=' AND p.usuario_id=:u';$a['u']=$_SESSION['usuario_id'];}$q=$pdo->prepare($sql);$q->execute($a);$id=(int)$q->fetchColumn();if(!$id){http_response_code(404);exit('Documento no disponible.');}header('Location:'.atenea_url('src/dte/documento.php?pedido='.$id));
